SELECT t1.*,t2.nick_name nickName FROM member_login_log t1
LEFT JOIN member t2 ON t1.member_id = t2.id


        AND t1.invoke_url LIKE concat('%',#{logLoginEntity.invokeUrl},'%')


        AND t1.remote_addr LIKE concat('%',#{logLoginEntity.remoteAddr},'%')


        AND t1.invoke_params LIKE concat('%',#{logLoginEntity.invokeParams},'%')


        AND t1.invoke_status = #{logLoginEntity.invokeStatus}


        AND t1.invoke_time BETWEEN #{logLoginEntity.invokeTimeStart} AND #{logLoginEntity.invokeTimeEnd}


        AND t1.elapsed_time LIKE concat('%',#{logLoginEntity.elapsedTime},'%')


        AND t1.member_id = #{logLoginEntity.memberId}


        AND t1.login_method = #{logLoginEntity.loginMethod}


ORDER BY invoke_time DESC

    limit #{map.offset},#{map.rows}

